class Solution:
    def smallestDistancePair(self, nums: List[int], k: int) -> int:
        nums.sort()
        n = len(nums)
        lo, hi = 0, nums[-1] - nums[0]
        def count(mid):
            c = j = 0
            for i in range(n):
                while j < n and nums[j] - nums[i] <= mid:
                    j += 1
                c += j - i - 1
            return c >= k
        while lo < hi:
            mid = (lo + hi) // 2
            if count(mid): hi = mid
            else: lo = mid + 1
        return lo

