class Solution {
public:
    int smallestDistancePair(vector<int>& nums, int k) {
        sort(nums.begin(), nums.end());
        int n = nums.size(), lo = 0, hi = nums.back() - nums[0];
        auto enough = [&](int mid){
            int c = 0, j = 0;
            for (int i = 0; i < n; i++) {
                while (j < n && nums[j] - nums[i] <= mid) j++;
                c += j - i - 1;
                if (c >= k) return true;
            }
            return false;
        };
        while (lo < hi) {
            int mid = lo + (hi - lo) / 2;
            if (enough(mid)) hi = mid;
            else lo = mid + 1;
        }
        return lo;
    }
};

